const base = $('Normalize AI Output').item.json;
const collapse = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const sanitizeReply = (value) => collapse(value)
  .replace(/[\*_#>`~]/g, '')
  .replace(/\[(.*?)\]\((.*?)\)/g, '$1')
  .replace(/\s+/g, ' ')
  .trim();
const buildVoiceReply = (value, maxChars = 190, maxSentences = 2) => {
  const cleaned = sanitizeReply(value);
  if (!cleaned) return '';
  const sentenceParts = cleaned.match(/[^.!?؟\n]+[.!?؟]?/g) || [cleaned];
  let candidate = sentenceParts.slice(0, maxSentences).join(' ').trim();
  if (!candidate) candidate = cleaned;
  if (candidate.length <= maxChars) return candidate;
  const cutoff = candidate.slice(0, maxChars);
  const boundary = Math.max(
    cutoff.lastIndexOf('. '),
    cutoff.lastIndexOf('! '),
    cutoff.lastIndexOf('? '),
    cutoff.lastIndexOf('؟ '),
    cutoff.lastIndexOf('، '),
    cutoff.lastIndexOf(', ')
  );
  if (boundary > 80) return cutoff.slice(0, boundary + 1).trim();
  return cutoff.trim().replace(/[,:;.!?؟،]+$/, '') + '...';
};
