let imageBase64 = null;
let imageMime = 'image/png';
let route = 'ok';
let errorCode = null;
let errorMessage = null;

try {
  // Strategy 1: Cloudflare returns JSON { result: { image: 'base64...' }, success: true }
  if ($json?.result?.image) {
    imageBase64 = $json.result.image;
  }
  // Strategy 2: image at top level of response
  else if ($json?.image) {
    imageBase64 = $json.image;
  }
  // Strategy 3: binary data (if responseFormat was 'file')
  else {
    const binaryKeys = Object.keys($binary || {});
    if (binaryKeys.length > 0) {
      const binaryData = $binary[binaryKeys[0]];
      if (binaryData?.mimeType?.startsWith('image/')) {
        imageBase64 = binaryData.data;
        imageMime = binaryData.mimeType;
      } else if (binaryData?.data) {
        // Binary might be JSON text — try to parse it
        try {
          const decoded = Buffer.from(binaryData.data, 'base64').toString('utf8');
          const parsed = JSON.parse(decoded);
          if (parsed?.result?.image) {
            imageBase64 = parsed.result.image;
          } else if (parsed?.image) {
            imageBase64 = parsed.image;
          }
        } catch (_) { /* not parseable, skip */ }
      }
    }
  }

  // Strategy 4: check body wrapper (fullResponse mode)
  if (!imageBase64 && $json?.body) {
    const body = typeof $json.body === 'string' ? JSON.parse($json.body) : $json.body;
    if (body?.result?.image) imageBase64 = body.result.image;
    else if (body?.image) imageBase64 = body.image;
  }

  // Check for Cloudflare API errors
  if (!imageBase64 && $json?.success === false) {
    route = 'image_gen_failed';
    errorCode = 'cloudflare_api_error';
    const cfErrors = $json?.errors;
    errorMessage = Array.isArray(cfErrors) && cfErrors.length > 0
      ? cfErrors.map(e => e.message || JSON.stringify(e)).join('; ')
      : 'Cloudflare API returned an error';
  } else if (!imageBase64) {
    route = 'image_gen_failed';
    errorCode = 'image_generation_failure';
    errorMessage = 'Image generation returned empty result';
  }
} catch (e) {
  route = 'image_gen_failed';
  errorCode = 'image_generation_failure';
  errorMessage = 'Failed to process image generation response: ' + e.message;
}

return {
  json: {
    ...base,
    image_base64: imageBase64,
    image_mime: imageMime,
    route,
    error_code: errorCode,
    error_message: errorMessage,
  },
};

